@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
    },
)
def build_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
) -> str:
    """
    """

    docker_file = pathlib.Path(
        DOT_DOCKER_ROOT,
        "generations",
        env_base.get("GENERATION", "default"),
        "Dockerfiles",
        context.asset_key.path[-1],
        "Dockerfile",
    )

    tags = [
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:latest",
        f"{env_base.get('IMAGE_PREFIX')}/{context.asset_key.path[-1]}:{str(time.time())}",
    ]

    # @formatter:off
    docker_file_str = textwrap.dedent("""
        # {auto_generated}
        # https://hub.docker.com/r/cgwire/cgwire
        FROM cgwire/cgwire:latest AS {image_name}
        LABEL authors="{AUTHOR}"
        
        WORKDIR /opt/zou
        
        ENTRYPOINT []
    """).format(
        auto_generated=f"AUTO-GENERATED by Dagster Asset {context.asset_key.path[-1]}",
        image_name=context.asset_key.path[-1],
        **env_base,
    )
    # @formatter:on

    shutil.rmtree(docker_file.parent, ignore_errors=True)

    docker_file.parent.mkdir(parents=True, exist_ok=True)

    with open(docker_file, "w") as fw:
        fw.write(docker_file_str)

    with open(docker_file, "r") as fr:
        docker_file_content = fr.read()

    stream = docker.build(
        context_path=docker_file.parent.as_posix(),
        cache=DOCKER_USE_CACHE,
        tags=tags,
        stream_logs=True,
    )

    log: str = ""

    for msg in stream:
        context.log.debug(msg)
        log += msg

    cmds_docker = compile_cmds(
        docker_file=docker_file,
        tag=tags[1],
    )

    yield Output(tags[1])

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            context.asset_key.path[-1]: MetadataValue.path(tags[1]),
            "docker_file": MetadataValue.md(f"```shell\n{docker_file_content}\n```"),
            **cmds_docker,
            "build_logs": MetadataValue.md(f"```shell\n{log}\n```"),
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
    },
)
def prepare_db_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
):

    # kitsu_db_dir_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION"))
    # kitsu_db_dir_host.mkdir(parents=True, exist_ok=True)

    # sudo chown 105:105 KitsuPostgres
    # Concept: /usr/bin/sshpass -eENV_VAR /usr/bin/ssh "echo $ENV_VAR | sudo -S <cmd>"
    # Because shutil.chown cannot sudo

    stdout_stderr = {
            "stdout": MetadataValue.md(f"```shell\nNone\n```"),
            "stderr": MetadataValue.md(f"```shell\nNone\n```"),
    }

    if not KITSUDB_INSIDE_CONTAINER:

        kitsu_db_dir_host = pathlib.Path(env_base.get("KITSU_DATABASE_INSTALL_DESTINATION"))
        kitsu_db_dir_host.mkdir(parents=True, exist_ok=True)

        kitsu_db_template = env_base.get("KITSU_TEMPLATE_DB_14")

        if not any(kitsu_db_dir_host.iterdir()):
            shutil.copytree(
                src=kitsu_db_template,
                dst=kitsu_db_dir_host,
                dirs_exist_ok=True,
            )

        context.log.info(f"Setting ownership of {kitsu_db_dir_host.as_posix()}...")

        script_out_dir = pathlib.Path(
            DOT_DOCKER_ROOT,
            "generations",
            env_base.get("GENERATION", "default"),
            "scripts",
            context.asset_key.path[-1],
        )

        script_out_dir.mkdir(parents=True, exist_ok=True)

        with tempfile.NamedTemporaryFile(
            mode="w",
            suffix=".sh",
            delete=False,
            prefix=f"{context.asset_key.path[-1]}__chown__",
            dir=script_out_dir
        ) as sh_chown:
            kitsu_postgres_uid = 105
            kitsu_postgres_gid = 105
            sh_chown.write("#!/bin/bash\n")
            sh_chown.write("\n")
            sh_chown.write(
                f"{shutil.which('sshpass')} -eSSH_PASS "
                f"ssh {env_base['SSH_USER']}@{env_base['SSH_HOST']} "
                f"\"echo $SSH_PASS | sudo -S chown -R {kitsu_postgres_uid}:{kitsu_postgres_gid} {kitsu_db_dir_host.as_posix()}\"\n")
            sh_chown.write("\n")
            sh_chown.write('# 2025-01-20 11:00:01.316 UTC [98] FATAL:  data directory "/var/lib/postgresql/14/main" has invalid permissions\n')
            sh_chown.write('# 2025-01-20 11:00:01.316 UTC [98] DETAIL:  Permissions should be u=rwx (0700) or u=rwx,g=rx (0750).\n')
            sh_chown.write(
                f"{shutil.which('sshpass')} -eSSH_PASS "
                f"ssh {env_base['SSH_USER']}@{env_base['SSH_HOST']} "
                f"\"echo $SSH_PASS | sudo -S chmod -R 0700 {kitsu_db_dir_host.as_posix()}\"\n")
            sh_chown.write("echo Success\n")
            sh_chown.write("exit 0\n")

        cmd = [
            shutil.which("bash"),
            sh_chown.name,
        ]

        proc = subprocess.Popen(
            cmd,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            env={
                "SSH_PASS": env_base['SSH_PASS'],
            }
        )

        stdout, stderr = proc.communicate()

        stdout_stderr = {
                "stdout": MetadataValue.md(f"```shell\n{stdout.decode(encoding='utf-8')}\n```"),
                "stderr": MetadataValue.md(f"```shell\n{stderr.decode(encoding='utf-8')}\n```"),
        }

        # helpers.iterate_fds(
        #     (
        #         proc.stderr,
        #         proc.stdout,
        #     ),
        #     (
        #         context.log.warning,
        #         context.log.info,
        #     )
        # )

    yield Output({})

    yield AssetMaterialization(
        asset_key=context.asset_key,
        metadata={
            "sh_chown": MetadataValue.path(sh_chown.name),
            **stdout_stderr,
            "env_base": MetadataValue.json(env_base),
        },
    )


@asset(
    group_name="Kitsu",
    compute_kind="python",
    ins={
        "env_base": AssetIn(),
        "build_kitsu": AssetIn(),
    },
    deps=[
        "prepare_db_kitsu",
    ],
)
def compose_kitsu(
        context: AssetExecutionContext,
        env_base: dict,
        build_kitsu: str,
) -> dict:
    """
    """

    # INIT_ZOU.SH
    script_init_zou = pathlib.Path(
        env_base.get('KITSU_INIT_ZOU'),
    )

    script_init_zou.parent.mkdir(parents=True, exist_ok=True)

    with open(
        file=script_init_zou,
        mode="w",
    ) as sh_init_zou:
        # Source:
        # /opt/zou/init_zou.sh
        kitsu_admin_user = env_base.get("KITSU_ADMIN_USER")
        kitsu_admin_password = env_base.get("KITSU_ADMIN_PASSWORD")

        sh_init_zou.write("#!/bin/bash\n")
        sh_init_zou.write("export LC_ALL=C.UTF-8\n")
        sh_init_zou.write("export LANG=C.UTF-8\n")
        sh_init_zou.write("\n")
        sh_init_zou.write("service postgresql start\n")
        sh_init_zou.write("service redis-server start\n")
        sh_init_zou.write("\n")
        sh_init_zou.write(". /opt/zou/env/bin/activate\n")
        sh_init_zou.write("\n")
        sh_init_zou.write("zou upgrade-db\n")
        sh_init_zou.write("zou init-data\n")
        sh_init_zou.write(f"zou create-admin {kitsu_admin_user} --password {kitsu_admin_password}\n")
        sh_init_zou.write("\n")
        sh_init_zou.write("service postgresql stop\n")
        sh_init_zou.write("service redis-server stop\n")
        sh_init_zou.write("\n")
        sh_init_zou.write("echo Success\n")
        sh_init_zou.write("\n")
        sh_init_zou.write("exit 0\n")

    # # INIT_AND_START_ZOU.SH
    # script_init_and_start_zou = pathlib.Path(
    #     env_base.get('KITSU_INIT_AND_START_ZOU'),
    # )
    #
    # script_init_and_start_zou.parent.mkdir(parents=True, exist_ok=True)
    #
    # with open(
    #     file=script_init_and_start_zou,
    #     mode="w",
    # ) as sh_init_and_start_zou:
    #     sh_init_and_start_zou.write("#!/bin/bash\n")
    #     sh_init_and_start_zou.write("export LC_ALL=C.UTF-8\n")
    #     sh_init_and_start_zou.write("export LANG=C.UTF-8\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("if [ -z \"$( ls -A '/var/lib/postgresql/14/main' )\" ]; then\n")
    #     sh_init_and_start_zou.write("\tbash /opt/zou/init_zou.sh\n")
    #     sh_init_and_start_zou.write("\techo \"Kitsu DB initialized successfully\"\n")
    #     sh_init_and_start_zou.write("fi\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("bash /opt/zou/start_zou.sh\n")
    #     # sh_init_and_start_zou.write("\n")
    #     # sh_init_and_start_zou.write("echo Success\n")
    #     sh_init_and_start_zou.write("\n")
    #     sh_init_and_start_zou.write("exit 0\n")

    # compile_cmds(
    #     docker_file=build_kitsu,
    #     tag=
    # )

    cmd_docker_run = [
        shutil.which("docker"),
        "run",
        "--rm",
        "--interactive",
        "--tty",
        build_kitsu,
        "/bin/bash",
    ]

    volumes = [
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT')}",
        f"{env_base.get('NFS_ENTRY_POINT')}:{env_base.get('NFS_ENTRY_POINT_LNS')}",
        # f"{env_base.get('KITSU_INIT_AND_START_ZOU')}:/opt/zou/init_and_start_zou.sh",
        f"{env_base.get('KITSU_INIT_ZOU')}:/opt/zou/init_zou.sh",
    ]

    if not KITSUDB_INSIDE_CONTAINER:

        # Todo:
        #  - [ ] Set ownership of kitsu_previews_host as well?
        #  - [ ] /opt/zou/zou?
        kitsu_previews_host = pathlib.Path(env_base.get("KITSU_PREVIEWS"))
        kitsu_previews_host.mkdir(parents=True, exist_ok=True)

        volumes.insert(
            0,
            f"{env_base.get('KITSU_DATABASE_INSTALL_DESTINATION')}:/var/lib/postgresql/14/main",
        )

        volumes.insert(
            1,
            f"{kitsu_previews_host}:/opt/zou/previews",
        )

        # volumes.insert(
